# Category: message_queue_security

import sys
import boto3

def create_sns_subscription(user_provided_url, topic):
    sns = boto3.client('sns')
    response = sns.subscribe(
        TopicArn=topic,
        Protocol='https',
        Endpoint=user_provided_url
    )
    return response['SubscriptionArn']

if __name__ == "__main__":
    topic = "your-topic-arn"  # Replace with your desired SNS Topic ARN
    user_provided_url = sys.argv[1]
    subscription_arn = create_sns_subscription(user_provided_url, topic)
    print(f"Subscription created for URL: {user_provided_url} with ARN: {subscription_arn}")